  );

-- audit_events: admin only select, insert allowed for service role
create policy "audit_admin_select" on public.audit_events for select
  using (get_my_role() = 'admin');

-- access_requests: admin sees all, anonymous can insert
create policy "access_req_admin" on public.access_requests for all
  using (get_my_role() = 'admin');
create policy "access_req_insert_anon" on public.access_requests for insert
  with check (true);

-- aircraft: client sees owned org, crew sees assigned, admin sees all
create policy "aircraft_select" on public.aircraft for select
  using (get_my_role() = 'admin' or get_my_role() = 'crew' or
    exists (select 1 from public.profiles p where p.id = auth.uid() and p.organization_id = aircraft.owner_org_id));
create policy "aircraft_admin_write" on public.aircraft for all using (get_my_role() = 'admin');

-- approvals
create policy "approvals_select" on public.approvals for select
  using (requested_from = auth.uid() or requested_by = auth.uid() or get_my_role() = 'admin');
create policy "approvals_update_owner" on public.approvals for update
  using (requested_from = auth.uid() or get_my_role() = 'admin');
create policy "approvals_admin_insert" on public.approvals for insert
  with check (get_my_role() = 'admin');
```

