128	export async function requirePortalSession(allowedRoles?: PortalRole[]) {
129	  // Try Supabase auth first
130	  try {
131	    const supabase = await createClient();
132	    const {
133	      data: { user },
134	    } = await supabase.auth.getUser();
135	
136	    if (user) {
137	      // Fetch role from profiles table (RLS enforces access)
138	      const { data: profile } = await supabase
139	        .from("profiles")
140	        .select("email, full_name, role")
141	        .eq("id", user.id)
142	        .single();
143	
144	      if (profile && isPortalRole(profile.role)) {
145	        const supabaseSession: PortalSession = {
146	          email: profile.email ?? user.email ?? "",
147	          name: profile.full_name ?? toDisplayName(profile.email ?? user.email ?? ""),
148	          role: profile.role as PortalRole,
149	          signedInAt: user.created_at ?? new Date().toISOString(),
150	        };
151	
152	        if (
153	          allowedRoles?.length &&
154	          !allowedRoles.includes(supabaseSession.role) &&
155	          supabaseSession.role !== "admin"
156	        ) {
157	          redirect(getPortalRole(supabaseSession.role).href);
158	        }
159	
160	        return supabaseSession;
161	      }
162	    }
163	  } catch {
164	    // Fall through to cookie-based session
165	  }
166	
167	  // Fallback: cookie-based session (backward compat during transition)
168	  const session = await getPortalSession();
169	
170	  if (!session) {
171	    redirect("/login");
172	  }
173	
174	  if (allowedRoles?.length && !allowedRoles.includes(session.role) && session.role !== "admin") {
175	    redirect(getPortalRole(session.role).href);
176	  }
177	
178	  return session;
179	}
