2	import { NextResponse, type NextRequest } from "next/server";
3	
4	export async function middleware(request: NextRequest) {
5	  let supabaseResponse = NextResponse.next({ request });
6	
7	  const supabase = createServerClient(
8	    process.env.NEXT_PUBLIC_SUPABASE_URL!,
9	    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
10	    {
11	      cookies: {
12	        getAll() {
13	          return request.cookies.getAll();
14	        },
15	        setAll(toSet) {
16	          toSet.forEach(({ name, value }) => request.cookies.set(name, value));
17	          supabaseResponse = NextResponse.next({ request });
18	          toSet.forEach(({ name, value, options }) =>
19	            supabaseResponse.cookies.set(name, value, options)
20	          );
21	        },
22	      },
23	    }
24	  );
25	
26	  const {
27	    data: { user },
28	  } = await supabase.auth.getUser();
29	
30	  if (!user && request.nextUrl.pathname.startsWith("/portal")) {
31	    const url = request.nextUrl.clone();
32	    url.pathname = "/login";
33	    return NextResponse.redirect(url);
34	  }
35	
36	  return supabaseResponse;
37	}
