-- Extend profiles into the full user model (additive, idempotent)
alter table public.profiles add column if not exists phone text;
alter table public.profiles add column if not exists company_name text;
alter table public.profiles add column if not exists status text not null default 'pending';
alter table public.profiles add column if not exists home_base text;
alter table public.profiles add column if not exists last_login_at timestamptz;

do $$ begin
  if not exists (select 1 from pg_constraint where conname = 'profiles_status_check') then
    alter table public.profiles add constraint profiles_status_check
      check (status in ('pending','approved','suspended'));
  end if;
end $$;

-- Drop empty, conflicting legacy operational tables (all 0 rows). CASCADE clears inter-table FKs.
drop table if exists public.crew_qualifications cascade;
drop table if exists public.crew_assignments cascade;
drop table if exists public.crew_availability cascade;
drop table if exists public.crew_profiles cascade;
drop table if exists public.assignments cascade;
drop table if exists public.vendor_tasks cascade;
drop table if exists public.approvals cascade;
drop table if exists public.support_requests cascade;
drop table if exists public.trips cascade;
drop table if exists public.notifications cascade;
drop table if exists public.audit_logs cascade;
drop table if exists public.aircraft cascade;

-- Clean aircraft table keyed to the owning client profile
create table public.aircraft (
  id uuid primary key default gen_random_uuid(),
  client_id uuid references public.profiles(id) on delete set null,
  tail_number text not null unique,
  make text,
  model text,
  serial_number text,
  year int,
  home_base text,
  aircraft_category text,
  passenger_capacity int,
  required_crew int default 2,
  baggage_notes text,
  range_notes text,
  avionics_notes text,
  maintenance_status text not null default 'in_service'
    check (maintenance_status in ('in_service','maintenance','aog','inactive')),
  status text not null default 'active' check (status in ('active','inactive')),
  notes text,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);
create index aircraft_client_idx on public.aircraft(client_id);

-- Extend documents with review lifecycle
alter table public.documents add column if not exists status text not null default 'pending_review';
do $$ begin
  if not exists (select 1 from pg_constraint where conname = 'documents_status_check') then
    alter table public.documents add constraint documents_status_check
      check (status in ('pending_review','approved','rejected','expiring','expired'));
  end if;
end $$;
alter table public.documents add column if not exists expiration_date date;
alter table public.documents add column if not exists reviewed_by uuid references public.profiles(id);
alter table public.documents add column if not exists review_notes text;
alter table public.documents add column if not exists mission_id uuid references public.missions(id) on delete cascade;

-- Extend messaging with visibility + mission linkage
alter table public.messages add column if not exists visibility text not null default 'all';
do $$ begin
  if not exists (select 1 from pg_constraint where conname = 'messages_visibility_check') then
    alter table public.messages add constraint messages_visibility_check
      check (visibility in ('all','internal_admin','client','crew','partner'));
  end if;
end $$;
alter table public.message_threads add column if not exists mission_id uuid references public.missions(id) on delete cascade;
alter table public.message_threads add column if not exists last_message_at timestamptz default now();

-- Shared updated_at trigger
create or replace function public.set_updated_at()
returns trigger language plpgsql as $$
begin new.updated_at = now(); return new; end;
$$;

do $$
declare t text;
begin
  foreach t in array array[
    'aircraft','missions','mission_partner_assignments','quotes','expenses','crew_credentials'
  ] loop
    execute format('drop trigger if exists set_updated_at_%1$s on public.%1$s;', t);
    execute format('create trigger set_updated_at_%1$s before update on public.%1$s for each row execute procedure public.set_updated_at();', t);
  end loop;
end $$;

-- Keep crew_profiles.updated_at fresh too (column name matches)
drop trigger if exists set_updated_at_crew_profiles on public.crew_profiles;
create trigger set_updated_at_crew_profiles before update on public.crew_profiles
  for each row execute procedure public.set_updated_at();

-- Helper: is the caller an approved admin?
create or replace function public.is_admin()
returns boolean language sql stable security definer set search_path = public as $$
  select exists (select 1 from public.profiles where id = auth.uid() and role = 'admin');
$$;

-- Helper: does caller have an accepted/offered crew assignment on a mission?
create or replace function public.is_crew_on_mission(p_mission uuid)
returns boolean language sql stable security definer set search_path = public as $$
  select exists (
    select 1 from public.mission_crew_assignments
    where mission_id = p_mission and crew_id = auth.uid()
  ) or exists (
    select 1 from public.missions where id = p_mission and assigned_crew_id = auth.uid()
  );
$$;

-- Helper: is caller a partner assigned to a mission?
create or replace function public.is_partner_on_mission(p_mission uuid)
returns boolean language sql stable security definer set search_path = public as $$
  select exists (
    select 1 from public.mission_partner_assignments
    where mission_id = p_mission and partner_id = auth.uid()
  );
$$;

alter table public.aircraft enable row level security;
alter table public.missions enable row level security;
alter table public.mission_passengers enable row level security;
alter table public.mission_crew_assignments enable row level security;
alter table public.mission_partner_assignments enable row level security;
alter table public.quotes enable row level security;
alter table public.quote_line_items enable row level security;
alter table public.expenses enable row level security;
alter table public.crew_profiles enable row level security;
alter table public.crew_credentials enable row level security;
alter table public.crew_availability enable row level security;
alter table public.notifications enable row level security;

-- AIRCRAFT
create policy aircraft_select on public.aircraft for select using (
  public.is_admin() or client_id = auth.uid() or public.get_my_role() = 'crew'
);
create policy aircraft_admin_write on public.aircraft for all using (public.is_admin()) with check (public.is_admin());

-- MISSIONS
create policy missions_select on public.missions for select using (
  public.is_admin()
  or client_id = auth.uid()
  or created_by = auth.uid()
  or public.is_crew_on_mission(id)
  or public.is_partner_on_mission(id)
);
create policy missions_insert on public.missions for insert with check (
  public.is_admin() or created_by = auth.uid() or client_id = auth.uid()
);
create policy missions_update on public.missions for update using (
  public.is_admin() or client_id = auth.uid()
) with check (public.is_admin() or client_id = auth.uid());
create policy missions_delete on public.missions for delete using (public.is_admin());

-- MISSION PASSENGERS
create policy mp_select on public.mission_passengers for select using (
  public.is_admin()
  or exists (select 1 from public.missions m where m.id = mission_id and m.client_id = auth.uid())
  or public.is_crew_on_mission(mission_id)
);
create policy mp_write on public.mission_passengers for all using (
  public.is_admin()
  or exists (select 1 from public.missions m where m.id = mission_id and m.client_id = auth.uid())
) with check (
  public.is_admin()
  or exists (select 1 from public.missions m where m.id = mission_id and m.client_id = auth.uid())
);

-- MISSION CREW ASSIGNMENTS
create policy mca_select on public.mission_crew_assignments for select using (
  public.is_admin()
  or crew_id = auth.uid()
  or exists (select 1 from public.missions m where m.id = mission_id and m.client_id = auth.uid())
);
create policy mca_crew_update on public.mission_crew_assignments for update using (
  public.is_admin() or crew_id = auth.uid()
) with check (public.is_admin() or crew_id = auth.uid());
create policy mca_admin_write on public.mission_crew_assignments for insert with check (public.is_admin());
create policy mca_admin_delete on public.mission_crew_assignments for delete using (public.is_admin());

-- MISSION PARTNER ASSIGNMENTS
create policy mpa_select on public.mission_partner_assignments for select using (
  public.is_admin() or partner_id = auth.uid()
);
create policy mpa_partner_update on public.mission_partner_assignments for update using (
  public.is_admin() or partner_id = auth.uid()
) with check (public.is_admin() or partner_id = auth.uid());
create policy mpa_admin_write on public.mission_partner_assignments for insert with check (public.is_admin());
create policy mpa_admin_delete on public.mission_partner_assignments for delete using (public.is_admin());

-- QUOTES (admin manages; client reads; approval handled server-side via service role)
create policy quotes_select on public.quotes for select using (
  public.is_admin() or client_id = auth.uid()
);
create policy quotes_admin_write on public.quotes for all using (public.is_admin()) with check (public.is_admin());

create policy qli_select on public.quote_line_items for select using (
  public.is_admin()
  or exists (select 1 from public.quotes q where q.id = quote_id and q.client_id = auth.uid())
);
create policy qli_admin_write on public.quote_line_items for all using (public.is_admin()) with check (public.is_admin());

-- EXPENSES
create policy expenses_select on public.expenses for select using (
  public.is_admin() or crew_id = auth.uid()
);
create policy expenses_crew_insert on public.expenses for insert with check (
  public.is_admin() or crew_id = auth.uid()
);
create policy expenses_update on public.expenses for update using (
  public.is_admin() or crew_id = auth.uid()
) with check (public.is_admin() or crew_id = auth.uid());
create policy expenses_delete on public.expenses for delete using (
  public.is_admin() or crew_id = auth.uid()
);

-- CREW PROFILES
create policy crew_profiles_rw on public.crew_profiles for all using (
  public.is_admin() or id = auth.uid()
) with check (public.is_admin() or id = auth.uid());

-- CREW CREDENTIALS
create policy crew_cred_select on public.crew_credentials for select using (
  public.is_admin() or crew_id = auth.uid()
);
create policy crew_cred_write on public.crew_credentials for all using (
  public.is_admin() or crew_id = auth.uid()
) with check (public.is_admin() or crew_id = auth.uid());

